  Fantasy: [
    {title:"Harry Potter",author:"J K Rowling",cover:"https://covers.openlibrary.org/b/isbn/9780439554930-L.jpg"},
    {title:"The Hobbit",author:"Tolkien",cover:"https://covers.openlibrary.org/b/isbn/9780345339683-L.jpg"},
    {title:"LOTR",author:"Tolkien",cover:"https://covers.openlibrary.org/b/isbn/9780618640157-L.jpg"},
    {title:"Percy Jackson",author:"Rick Riordan",cover:"https://covers.openlibrary.org/b/isbn/9780786838653-L.jpg"},
    {title:"Narnia",author:"C S Lewis",cover:"https://covers.openlibrary.org/b/isbn/9780064471190-L.jpg"},
    {title:"Eragon",author:"Paolini",cover:"https://covers.openlibrary.org/b/isbn/9780375826696-L.jpg"},
    {title:"Mistborn",author:"Sanderson",cover:"https://covers.openlibrary.org/b/isbn/9780765350381-L.jpg"},
    {title:"Stormlight",author:"Sanderson",cover:"https://covers.openlibrary.org/b/isbn/9780765326355-L.jpg"},
    {title:"Witcher",author:"Sapkowski",cover:"https://covers.openlibrary.org/b/isbn/9780316029186-L.jpg"},
    {title:"Good Omens",author:"Gaiman",cover:"https://covers.openlibrary.org/b/isbn/9780060853983-L.jpg"}
  ],

  Business: [
    {title:"Zero to One",author:"Peter Thiel",cover:"https://covers.openlibrary.org/b/isbn/9780804139298-L.jpg"},
    {title:"The Lean Startup",author:"Eric Ries",cover:"https://covers.openlibrary.org/b/isbn/9780307887894-L.jpg"},
    {title:"Start With Why",author:"Simon Sinek",cover:"https://covers.openlibrary.org/b/isbn/9781591846444-L.jpg"},
    {title:"Good to Great",author:"Jim Collins",cover:"https://covers.openlibrary.org/b/isbn/9780066620993-L.jpg"},
    {title:"Blue Ocean Strategy",author:"Kim",cover:"https://covers.openlibrary.org/b/isbn/9781591396192-L.jpg"}
  ],

  Technology: [
    {title:"Clean Code",author:"Robert Martin",cover:"https://covers.openlibrary.org/b/isbn/9780132350884-L.jpg"},
    {title:"Design Patterns",author:"GoF",cover:"https://covers.openlibrary.org/b/isbn/9780201633610-L.jpg"},
    {title:"Refactoring",author:"Martin Fowler",cover:"https://covers.openlibrary.org/b/isbn/9780201485677-L.jpg"},
    {title:"You Don't Know JS",author:"Kyle Simpson",cover:"https://covers.openlibrary.org/b/isbn/9781491904244-L.jpg"}
  ],

  Literature: [
    { title: "Hamlet", author: "William Shakespeare", cover: "https://covers.openlibrary.org/b/isbn/9780743477123-L.jpg" },
    { title: "Macbeth", author: "William Shakespeare", cover: "https://covers.openlibrary.org/b/isbn/9780743477109-L.jpg" },
    { title: "Pride and Prejudice", author: "Jane Austen", cover: "https://covers.openlibrary.org/b/isbn/9780141439518-L.jpg" },
    { title: "Jane Eyre", author: "Charlotte Bronte", cover: "https://covers.openlibrary.org/b/isbn/9780141441146-L.jpg" }
  ]
};
// src/pages/CategoryBooksData.js

export const categoryBooks = {
  Fiction: [
    {
      id: 1,
      title: "The Alchemist",
      author: "Paulo Coelho",
      image: "https://covers.openlibrary.org/b/id/8231856-L.jpg",
      description: "A philosophical story about destiny and following dreams."
    },
    {
      id: 2,
      title: "The Kite Runner",
      author: "Khaled Hosseini",
      image: "https://covers.openlibrary.org/b/id/8226191-L.jpg",
      description: "A powerful tale of friendship, betrayal, and redemption."
    },
    {
      id: 3,
      title: "1984",
      author: "George Orwell",
      image: "https://covers.openlibrary.org/b/id/7222246-L.jpg",
      description: "A dystopian novel about surveillance and totalitarianism."
    },
    {
      id: 4,
      title: "The Book Thief",
      author: "Markus Zusak",
      image: "https://covers.openlibrary.org/b/id/8235116-L.jpg",
      description: "A story of words, war, and humanity narrated by Death."
    },
    {
      id: 5,
      title: "Life of Pi",
      author: "Yann Martel",
      image: "https://covers.openlibrary.org/b/id/8100906-L.jpg",
      description: "A survival story filled with faith and imagination."
    },
    {
      id: 6,
      title: "The Great Gatsby",
      author: "F. Scott Fitzgerald",
      image: "https://covers.openlibrary.org/b/id/7222161-L.jpg",
      description: "A tragic tale of love, wealth, and illusion."
    },
    {
      id: 7,
      title: "To Kill a Mockingbird",
      author: "Harper Lee",
      image: "https://covers.openlibrary.org/b/id/8228691-L.jpg",
      description: "A novel about justice, race, and moral growth."
    },
    {
      id: 8,
      title: "The Fault in Our Stars",
      author: "John Green",
      image: "https://covers.openlibrary.org/b/id/7267108-L.jpg",
      description: "A heartfelt story of love and loss."
    },
    {
      id: 9,
      title: "Little Women",
      author: "Louisa May Alcott",
      image: "https://covers.openlibrary.org/b/id/8231854-L.jpg",
      description: "A classic story of sisterhood and growing up."
    },
    {
      id: 10,
      title: "A Thousand Splendid Suns",
      author: "Khaled Hosseini",
      image: "https://covers.openlibrary.org/b/id/8155415-L.jpg",
      description: "A moving story about resilience and womanhood."
    },
    {
      id: 11,
      title: "The Catcher in the Rye",
      author: "J.D. Salinger",
      image: "https://covers.openlibrary.org/b/id/8231996-L.jpg",
      description: "A classic novel of teenage alienation."
    },
    {
      id: 12,
      title: "The Night Circus",
      author: "Erin Morgenstern",
      image: "https://covers.openlibrary.org/b/id/8155443-L.jpg",
      description: "A magical competition set in a mysterious circus."
    },
    {
      id: 13,
      title: "Normal People",
      author: "Sally Rooney",
      image: "https://covers.openlibrary.org/b/id/9259256-L.jpg",
      description: "An intimate story of love and relationships."
    },
    {
      id: 14,
      title: "The Shadow of the Wind",
      author: "Carlos Ruiz Zafón",
      image: "https://covers.openlibrary.org/b/id/8235118-L.jpg",
      description: "A mystery centered around forgotten books."
    },
    {
      id: 15,
      title: "The Time Traveler’s Wife",
      author: "Audrey Niffenegger",
      image: "https://covers.openlibrary.org/b/id/8231858-L.jpg",
      description: "A love story that transcends time."
    }
  ]
};

function CategoryBooks() {
  const { name } = useParams();
  const books = data[name] || [];

  return (
    <div className="books-page">
      <h1 className="books-title">{name}</h1>

      <div className="books-grid">
        {books.map((b, i) => (
          <div key={i} className="book-card-vertical">

  <div className="book-image-box">
    <img src={b.cover} alt={b.title} />
  </div>

  <h3 className="book-title">{b.title}</h3>
  <p className="book-author">{b.author}</p>

  <div className="book-status">AVAILABLE</div>

</div>

        ))}
      </div>
    </div>
  );
}

export default CategoryBooks;
